/* BTSlider — slider atom (Figma 434:7617)
 *
 * Types:   default (horizontal · 1 thumb)
 *          range   (horizontal · 2 thumbs)
 *          vertical (rotated · 1 thumb)
 *
 * Variants: primary · secondary · destructive
 *
 * Architecture:
 *   - .bt-slider            root container  (position: relative)
 *   - .bt-slider__track     inactive background bar
 *   - .bt-slider__fill      active segment (width/left/right via inline style)
 *   - .bt-slider__input     native <input type="range"> — invisible (opacity:0),
 *                           handles a11y + keyboard + pointer interaction
 *   - .bt-slider__thumb     visual circle positioned via JS
 *   - .bt-slider__tooltip   value callout above the thumb
 */

/* ── CSS custom properties (set per variant) ─────────────────────────────── */

.bt-slider--primary {
  --bt-slider-active:   var(--icon-primary);
  --bt-slider-inactive: color-mix(in srgb, var(--icon-primary) 25%, transparent);
  --bt-slider-thumb:    var(--icon-inverse);
}

.bt-slider--destructive {
  --bt-slider-active:   var(--icon-error);
  --bt-slider-inactive: color-mix(in srgb, var(--icon-error) 25%, transparent);
  --bt-slider-thumb:    var(--icon-error);
}

/* ── Root ────────────────────────────────────────────────────────────────── */

.bt-slider {
  position: relative;
  display: inline-flex;
  align-items: center;
  touch-action: none;
}

.bt-slider--horizontal {
  width: 100%;
  height: 24px; /* thumb diameter */
}

.bt-slider--vertical {
  flex-direction: column;
  width: 27px;   /* Figma: w-[27px] */
  height: 200px; /* Figma: h-[200px] */
  justify-content: center;
}

/* ── Track ───────────────────────────────────────────────────────────────── */

.bt-slider__track {
  position: absolute;
  border-radius: 9999px;
  background: var(--bt-slider-inactive);
  overflow: visible;
}

.bt-slider--horizontal .bt-slider__track {
  inset-inline-start: 12px;
  inset-inline-end: 12px;
  height: 4px;
}

.bt-slider--vertical .bt-slider__track {
  top: 12px;
  bottom: 12px;
  width: 4px;
  left: 50%;
  transform: translateX(-50%);
}

/* ── Fill ────────────────────────────────────────────────────────────────── */

.bt-slider__fill {
  position: absolute;
  background: var(--bt-slider-active);
  border-radius: 9999px;
}

.bt-slider--horizontal .bt-slider__fill {
  top: 0;
  bottom: 0;
  /* left + right set via inline style */
}

.bt-slider--vertical .bt-slider__fill {
  left: 0;
  right: 0;
  bottom: 0;
  /* height set via inline style */
}

/* ── Native input (invisible — interaction only) ─────────────────────────── */

.bt-slider__input {
  position: absolute;
  opacity: 0;
  cursor: pointer;
  margin: 0;
  z-index: 3;
}

.bt-slider--horizontal .bt-slider__input {
  inset: 0;
  width: 100%;
  height: 100%;
}

/* Two-input range: both inputs cover full track; z-index decides priority */
.bt-slider__input--start,
.bt-slider__input--end {
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: all;
}

.bt-slider--vertical .bt-slider__input {
  /* Rotate so it runs bottom→top */
  width: 200px;
  height: 27px;
  top: 0;
  left: 50%;
  transform: rotate(-90deg) translateX(-100%);
  transform-origin: left top;
  /* Invert: value=100 at top, value=0 at bottom */
}

/* ── Visual thumb ────────────────────────────────────────────────────────── */

.bt-slider__thumb {
  position: absolute;
  box-sizing: border-box; /* keep total ⌀ at 24px incl. 2.5px border */
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: var(--bt-slider-thumb);
  border: 2.5px solid var(--border-primary);
  pointer-events: none; /* input handles interaction */
  z-index: 2;
  transform: translateX(-50%);
  transition: box-shadow 0.15s;
}

.bt-slider--vertical .bt-slider__thumb {
  transform: translate(-50%, 50%);
  left: 50%;
  /* bottom set via inline style */
}

/* ── Overlay halo (icon.primary 50%) on hover/focus/active ─────────────── */
/* Single slider: scope to the non-modifier input/thumb so the generic rule
   does NOT bleed onto range thumbs (which share the base classes). */
.bt-slider__input:not(.bt-slider__input--start):not(.bt-slider__input--end):hover ~ .bt-slider__thumb:not(.bt-slider__thumb--start):not(.bt-slider__thumb--end),
.bt-slider__input:not(.bt-slider__input--start):not(.bt-slider__input--end):focus-visible ~ .bt-slider__thumb:not(.bt-slider__thumb--start):not(.bt-slider__thumb--end),
.bt-slider__input:not(.bt-slider__input--start):not(.bt-slider__input--end):active ~ .bt-slider__thumb:not(.bt-slider__thumb--start):not(.bt-slider__thumb--end) {
  box-shadow: 0 0 0 6px color-mix(in srgb, var(--icon-primary) 50%, transparent);
}

/* Range slider: each thumb's halo is driven ONLY by its own input, so dragging
   start never lights the end thumb (and vice versa). */
.bt-slider__input--start:hover ~ .bt-slider__thumb--start,
.bt-slider__input--start:focus-visible ~ .bt-slider__thumb--start,
.bt-slider__input--start:active ~ .bt-slider__thumb--start,
.bt-slider__input--end:hover ~ .bt-slider__thumb--end,
.bt-slider__input--end:focus-visible ~ .bt-slider__thumb--end,
.bt-slider__input--end:active ~ .bt-slider__thumb--end {
  box-shadow: 0 0 0 6px color-mix(in srgb, var(--icon-primary) 50%, transparent);
}

/* ── Tooltip ─────────────────────────────────────────────────────────────── */

/* Figma 434:7544 — dark pill (bg.inverse #292f37) + 16×8px downward arrow */
.bt-slider__tooltip {
  position: absolute;
  background: var(--bg-inverse);
  color: var(--text-inverse);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);       /* fontSize.sm */
  font-weight: 500;
  line-height: var(--typography-line-height-xs);     /* lineHeight.xs */
  padding: var(--space-sm) var(--space-md);     /* spacing.sm × spacing.md */
  border-radius: var(--radius-md);    /* 8px */
  white-space: nowrap;
  pointer-events: none;
  z-index: 10;
}

/* Downward arrow — 16×8px (Figma 434:7544) */
.bt-slider__tooltip::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  border-left: 8px solid transparent;
  border-right: 8px solid transparent;
  border-top: 8px solid var(--bg-inverse);
  border-bottom: none;
}

/* Horizontal: tooltip pill sits 2px above thumb top.
 * Container height = 24px (= thumb ⌀).
 * bottom = 24px + arrow(8px) + gap(2px) = 34px = calc(100% + 10px).
 * Arrow tip ends up at -2px from container top = 2px above thumb. */
.bt-slider--horizontal .bt-slider__tooltip {
  bottom: calc(100% + 10px);
  top: auto;
  transform: translateX(-50%);
  /* left set inline: calc(ratio * (100% - 24px) + 12px) */
}

/* Vertical: tooltip pill to the left, centered on thumb.
 * bottom (inline) = ratio * (100% - 24px)  [no +12px — translateY(50%) handles centering]
 * Arrow points right toward the thumb. */
.bt-slider--vertical .bt-slider__tooltip {
  top: auto;
  left: auto;
  right: calc(100% + 6px);
  transform: translateY(50%);
}

/* Right-pointing arrow for vertical (6×12px) */
.bt-slider--vertical .bt-slider__tooltip::after {
  bottom: auto;
  left: auto;
  top: 50%;
  right: -6px;
  transform: translateY(-50%);
  border-top: 6px solid transparent;
  border-bottom: 6px solid transparent;
  border-left: 6px solid var(--bg-inverse);
  border-right: none;
}

/* ── Disabled ────────────────────────────────────────────────────────────── */

.bt-slider--disabled {
  opacity: 0.45;
  pointer-events: none;
}

/* ── Field wrapper (label/helper/error) — used when label/helperText/errorText set */

.bt-slider-field {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-slider-field__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

.bt-slider-field__required {
  color: var(--color-ext-error-bold);
  margin-inline-start: 2px;
}

.bt-slider-field__hint {
  font-size: var(--typography-font-size-xs);
  color: var(--text-secondary);
  line-height: var(--typography-line-height-xs);
  margin: 0;
}

.bt-slider-field__hint--error {
  color: var(--color-ext-error-bold);
}

/**
 * BTSlider — interactive range slider atom (Figma 434:7617).
 *
 * Three layout types: 'default' (horizontal · 1 thumb), 'range'
 * (horizontal · 2 thumbs), 'vertical' (1 thumb).
 * Three color variants: 'primary' · 'secondary' · 'destructive'.
 *
 * @example
 * ```tsx
 * // Default horizontal slider (controlled)
 * const [brightness, setBrightness] = useState(50);
 * <BTSlider value={brightness} onValueChange={setBrightness} />
 *
 * // Range slider
 * const [from, setFrom] = useState(20);
 * const [to, setTo] = useState(80);
 * <BTSlider type="range" startValue={from} endValue={to}
 *   onStartValueChange={setFrom} onEndValueChange={setTo} />
 *
 * // Vertical destructive slider
 * <BTSlider type="vertical" variant="destructive" value={level}
 *   onValueChange={setLevel} />
 * ```
 */
import { useState, useCallback, useRef, useEffect, useId } from 'react';
import './BTSlider.css';
import type { BTSliderProps } from './BTSlider.types';
import { useBTForm } from '../form/BTFormContext';

function toRatio(v: number, min: number, max: number) {
  return (v - min) / (max - min);
}
function clamp(v: number, min: number, max: number) {
  return Math.min(max, Math.max(min, v));
}
function hLeft(ratio: number, rtl: boolean) {
  const r = rtl ? 1 - ratio : ratio;
  return `calc(${r} * (100% - 24px) + 12px)`;
}

export function BTSlider({
  type = 'default',
  variant = 'primary',
  value: valueProp,
  startValue: startProp,
  endValue: endProp,
  min = 0,
  max = 100,
  step = 1,
  showTooltip = true,
  alwaysShown = false,
  disabled = false,
  name,
  label,
  required,
  helperText,
  errorText,
  onValueChange,
  onStartValueChange,
  onEndValueChange,
  className,
}: BTSliderProps) {
  // ── BTForm wiring (default/vertical types only) ─────────────────────────
  const form = useBTForm();
  const isInForm = form !== null && typeof name === 'string' && type !== 'range';
  const formValue = isInForm ? (form.values[name] as number | undefined) : undefined;
  const formError = isInForm ? form.errorFor(name) : null;
  const resolvedError = errorText ?? formError ?? undefined;
  const hasError = !!resolvedError;
  const reactId = useId();
  const fieldId = `bt-slider-${reactId}`;
  const hintId = `${fieldId}-hint`;
  // ── Internal state ──────────────────────────────────────────────────────
  const [_value, _setValue] = useState(() => valueProp ?? Math.round((min + max) / 2));
  const [_start, _setStart] = useState(() => startProp ?? min + Math.round((max - min) * 0.2));
  const [_end,   _setEnd]   = useState(() => endProp   ?? max - Math.round((max - min) * 0.2));

  const val   = valueProp !== undefined ? valueProp : formValue ?? _value;
  const start = startProp !== undefined ? startProp : _start;
  const end   = endProp   !== undefined ? endProp   : _end;

  // ── RTL detection ───────────────────────────────────────────────────────
  const rootRef = useRef<HTMLDivElement>(null);
  const [rtl, setRtl] = useState(false);

  useEffect(() => {
    const check = () =>
      setRtl(!!rootRef.current && getComputedStyle(rootRef.current).direction === 'rtl');
    check();
    const obs = new MutationObserver(check);
    obs.observe(document.documentElement, { attributes: true, attributeFilter: ['dir'] });
    return () => obs.disconnect();
  }, []);

  // ── Dragging state (tooltip show-on-drag) ───────────────────────────────
  const [valDragging,   setValDragging]   = useState(false);
  const [startDragging, setStartDragging] = useState(false);
  const [endDragging,   setEndDragging]   = useState(false);

  const showVal   = showTooltip && (alwaysShown || valDragging);
  const showStart = showTooltip && (alwaysShown || startDragging);
  const showEnd   = showTooltip && (alwaysShown || endDragging);

  // ── Derived styles ──────────────────────────────────────────────────────
  const fillStyle = (() => {
    if (type === 'range') {
      return {
        insetInlineStart: `${toRatio(start, min, max) * 100}%`,
        insetInlineEnd:   `${(1 - toRatio(end, min, max)) * 100}%`,
      };
    }
    if (type === 'vertical') {
      return { height: `${toRatio(val, min, max) * 100}%` };
    }
    return {
      insetInlineStart: '0%',
      insetInlineEnd:   `${(1 - toRatio(val, min, max)) * 100}%`,
    };
  })();

  const thumbStyle      = { left: hLeft(toRatio(val,   min, max), rtl) };
  const thumbStartStyle = { left: hLeft(toRatio(start, min, max), rtl) };
  const thumbEndStyle   = { left: hLeft(toRatio(end,   min, max), rtl) };
  const vThumbStyle     = { bottom: `calc(${toRatio(val, min, max)} * (100% - 24px))`, left: '50%' };
  const vTooltipStyle   = { bottom: `calc(${toRatio(val, min, max)} * (100% - 24px))` };
  const tooltipStyle    = { left: hLeft(toRatio(val,   min, max), rtl) };
  const ttStartStyle    = { left: hLeft(toRatio(start, min, max), rtl) };
  const ttEndStyle      = { left: hLeft(toRatio(end,   min, max), rtl) };

  // Range: clip each input to its half (split at midpoint between thumbs).
  // clip-path uses physical coords — must account for RTL.
  const midRatio = (toRatio(start, min, max) + toRatio(end, min, max)) / 2;
  const physMid  = rtl ? (1 - midRatio) * 100 : midRatio * 100;
  const startInputStyle = {
    clipPath: rtl ? `inset(0 0 0 ${physMid}%)` : `inset(0 ${100 - physMid}% 0 0)`,
  };
  const endInputStyle = {
    clipPath: rtl ? `inset(0 ${100 - physMid}% 0 0)` : `inset(0 0 0 ${physMid}%)`,
  };

  // ── Handlers ────────────────────────────────────────────────────────────
  const onValueInput = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = clamp(Number(e.target.value), min, max);
      _setValue(v);
      onValueChange?.(v);
      if (isInForm) form.setField(name, v);
    },
    [min, max, onValueChange, isInForm, form, name],
  );

  const onSliderBlur = useCallback(() => {
    if (isInForm) form.touch(name);
  }, [isInForm, form, name]);

  const onStartInput = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = clamp(Math.min(Number(e.target.value), end - step), min, max);
      _setStart(v);
      onStartValueChange?.(v);
    },
    [min, max, step, end, onStartValueChange],
  );

  const onEndInput = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = clamp(Math.max(Number(e.target.value), start + step), min, max);
      _setEnd(v);
      onEndValueChange?.(v);
    },
    [min, max, step, start, onEndValueChange],
  );

  const rootClass = [
    'bt-slider',
    type === 'vertical' ? 'bt-slider--vertical' : 'bt-slider--horizontal',
    `bt-slider--${variant}`,
    disabled ? 'bt-slider--disabled' : '',
    className ?? '',
  ]
    .filter(Boolean)
    .join(' ');

  const showField = !!(label || helperText || resolvedError);
  const fieldHint = resolvedError ?? helperText;

  function wrapField(body: React.ReactNode) {
    if (!showField) return body;
    return (
      <div
        className={['bt-slider-field', hasError ? 'bt-slider-field--error' : '']
          .filter(Boolean)
          .join(' ')}
      >
        {label && (
          <label htmlFor={fieldId} className="bt-slider-field__label">
            {label}
            {required && <span className="bt-slider-field__required" aria-hidden>*</span>}
          </label>
        )}
        {body}
        {fieldHint && (
          <p
            id={hintId}
            className={['bt-slider-field__hint', hasError ? 'bt-slider-field__hint--error' : '']
              .filter(Boolean)
              .join(' ')}
            role={hasError ? 'alert' : undefined}
          >
            {fieldHint}
          </p>
        )}
      </div>
    );
  }

  // ── Single-thumb template ───────────────────────────────────────────────
  if (type !== 'range') {
    return wrapField(
      <div ref={rootRef} className={rootClass}>
        {showVal && (
          <div
            className="bt-slider__tooltip"
            style={type === 'vertical' ? vTooltipStyle : tooltipStyle}
          >
            {val}
          </div>
        )}

        <div className="bt-slider__track">
          <div className="bt-slider__fill" style={fillStyle} />
        </div>

        <input
          id={fieldId}
          name={name}
          className="bt-slider__input"
          type="range"
          min={min}
          max={max}
          step={step}
          value={val}
          disabled={disabled}
          aria-orientation={type === 'vertical' ? 'vertical' : 'horizontal'}
          aria-valuemin={min}
          aria-valuemax={max}
          aria-valuenow={val}
          aria-invalid={hasError || undefined}
          aria-required={required || undefined}
          aria-describedby={fieldHint ? hintId : undefined}
          onChange={onValueInput}
          onBlur={onSliderBlur}
          onPointerDown={() => setValDragging(true)}
          onPointerUp={() => setValDragging(false)}
          onPointerCancel={() => setValDragging(false)}
        />

        <div
          className="bt-slider__thumb"
          style={type === 'vertical' ? vThumbStyle : thumbStyle}
        />
      </div>
    );
  }

  // ── Range (two thumbs) template ─────────────────────────────────────────
  return wrapField(
    <div ref={rootRef} className={rootClass}>
      {showStart && <div className="bt-slider__tooltip" style={ttStartStyle}>{start}</div>}
      {showEnd   && <div className="bt-slider__tooltip" style={ttEndStyle}>{end}</div>}

      <div className="bt-slider__track">
        <div className="bt-slider__fill" style={fillStyle} />
      </div>

      <input
        className="bt-slider__input bt-slider__input--start"
        type="range"
        style={startInputStyle}
        min={min}
        max={max}
        step={step}
        value={start}
        disabled={disabled}
        aria-label="Range start"
        onChange={onStartInput}
        onPointerDown={() => setStartDragging(true)}
        onPointerUp={() => setStartDragging(false)}
        onPointerCancel={() => setStartDragging(false)}
      />
      <input
        className="bt-slider__input bt-slider__input--end"
        type="range"
        style={endInputStyle}
        min={min}
        max={max}
        step={step}
        value={end}
        disabled={disabled}
        aria-label="Range end"
        onChange={onEndInput}
        onPointerDown={() => setEndDragging(true)}
        onPointerUp={() => setEndDragging(false)}
        onPointerCancel={() => setEndDragging(false)}
      />

      <div className="bt-slider__thumb bt-slider__thumb--start" style={thumbStartStyle} />
      <div className="bt-slider__thumb bt-slider__thumb--end"   style={thumbEndStyle} />
    </div>
  );
}

BTSlider.displayName = 'BTSlider';

// BTSlider types — Figma source: node 434:7617.

/** Layout and thumb count. */
export type BTSliderType = 'default' | 'range' | 'vertical';

/**
 * Color variant of the active track + thumb (Figma 434:7227).
 * - primary     → icon.primary  (#292f37)
 * - destructive → icon.error    (#991515)
 */
export type BTSliderVariant = 'primary' | 'destructive';

export interface BTSliderProps {
  /**
   * Layout type.
   * - 'default'  → horizontal, single thumb
   * - 'range'    → horizontal, two thumbs (start + end)
   * - 'vertical' → vertical, single thumb
   * @default 'default'
   */
  type?: BTSliderType;
  /**
   * Color variant for active track and thumb.
   * @default 'primary'
   */
  variant?: BTSliderVariant;
  /** Controlled value for default / vertical types. */
  value?: number;
  /** Controlled start value for range type. */
  startValue?: number;
  /** Controlled end value for range type. */
  endValue?: number;
  /** Minimum selectable value. @default 0 */
  min?: number;
  /** Maximum selectable value. @default 100 */
  max?: number;
  /** Increment step. @default 1 */
  step?: number;
  /** Show value tooltip above (or beside for vertical) the thumb. @default true */
  showTooltip?: boolean;
  /**
   * When `true` the tooltip is always visible (default).
   * When `false` the tooltip only appears on hover / keyboard focus.
   * Has no effect when `showTooltip` is `false`.
   * @default true
   */
  alwaysShown?: boolean;
  /** Disables all interaction. @default false */
  disabled?: boolean;
  /**
   * Field name — when set inside a `<BTForm>` (default/vertical types only),
   * auto-wires `value` and `onValueChange`. Range type ignores this since
   * its state is two-valued.
   */
  name?: string;
  /** Label rendered above the slider track. */
  label?: string;
  /** Marks the field as required (renders red asterisk after the label). */
  required?: boolean;
  /** Helper text rendered below the slider. Hidden when `errorText` is set. */
  helperText?: string;
  /** Error message rendered below the slider, overrides `helperText`. */
  errorText?: string;
  /** Called when the single value changes. */
  onValueChange?: (value: number) => void;
  /** Called when the range start value changes. */
  onStartValueChange?: (value: number) => void;
  /** Called when the range end value changes. */
  onEndValueChange?: (value: number) => void;
  /** Additional CSS class names. */
  className?: string;
}
